proof fn phi_1_eventually_proved_by_witness_intensional_bridge(ex: Execution<int>, p: TempPred<int>, witness_idx: nat)
    requires
        p.satisfied_by(ex.suffix(witness_idx)),
    ensures
        eventually(p).satisfied_by(ex),
{
    eventually_proved_by_witness::<int>(ex, p, witness_idx);
}

proof fn phi_2_execution_equality_forces_fn_equality(f: spec_fn(nat) -> int, g: spec_fn(nat) -> int)
    requires
        forall |i: nat| #[trigger] f(i) == g(i),
    ensures
        f == g,
{
    let ex1 = Execution { nat_to_state: f };
    let ex2 = Execution { nat_to_state: g };
    execution_equality::<int>(ex1, ex2);
}

proof fn phi_3_suffix_zero_equals_self(ex: Execution<int>)
    ensures
        ex.suffix(0) == ex,
{
    execution_equality::<int>(ex.suffix(0), ex);
}

proof fn phi_4_suffix_composition_equals_addition(ex: Execution<int>, a: nat, b: nat)
    ensures
        ex.suffix(a).suffix(b) == ex.suffix(a + b),
{
    execution_equality::<int>(ex.suffix(a).suffix(b), ex.suffix(a + b));
}

proof fn phi_5_leads_to_self_any_pred(p: TempPred<int>)
    ensures
        valid(p.leads_to(p)),
